importScript:
const scheduleCode = {}

  // A helper function to convert a time string like "08:00" to minutes from midnight
  const timeToMinutes = (timeStr) => {
    if (!timeStr) return 0;
    const [hours, minutes] = timeStr.split(":").map(Number);
    return hours * 60 + minutes;
  };

  // A map to convert Arabic day names to a numerical index (0 for Saturday, etc.)
  const dayMap = {
    السبت: 0,
    الأحد: 1,
    الإثنين: 2,
    الثلاثاء: 3,
    الإربعاء: 4,
    الخميس: 5,
  };

  // Select the main schedule table from the page
  const table = document.querySelector(
    'table[cellspacing="0"][cellpadding="7"]'
  );

  if (!table) {
    console.error(
      "Schedule table not found. Make sure the HTML is loaded correctly."
    );
    return;
  }

  const rows = table.querySelectorAll("tr");

  // --- Step 1: Parse the time slots from the header row (08:00-09:30, etc.) ---
  const timeHeaderCells = Array.from(rows[0].querySelectorAll("td")).slice(1);
  const timeSlots = timeHeaderCells.map((cell) => {
    const timeText = cell.textContent.trim();
    const [start, end] = timeText.split(" - ");
    return {
      startTime: timeToMinutes(start),
      endTime: timeToMinutes(end),
    };
  });

  // --- Step 2: Iterate through each day's row to extract course data ---
  // Start from the second row (index 1) to skip the header
  for (let i = 1; i < rows.length; i++) {
    const cells = rows[i].querySelectorAll("td");
    const dayName = cells[0].textContent.trim();
    const dayIndex = dayMap[dayName];

    // Continue only if the row corresponds to a valid day
    if (dayIndex === undefined) {
      continue;
    }

    // --- Step 3: Iterate through each time slot cell for that day ---
    for (let j = 1; j < cells.length; j++) {
      const courseCell = cells[j];

             courseLink = courseCell.querySelector("p[title]");
             if (courseLink) {

        // Extract all the details from the HTML elements
        const courseName = courseLink.getAttribute("title").trim();
        const courseCode = courseLink.textContent.trim();

        const detailsDiv = courseCell.querySelector("div");
        const doctor = detailsDiv.childNodes[0].textContent.trim();
        const place = detailsDiv.querySelector("a[title='القاعة']").textContent.trim().replace(/[()]/g, "");

        // Get the start and end time based on the column index of the cell
        const { startTime, endTime } = timeSlots[j - 1];
        console.log(courseCode, startTime, endTime);
        // --- Step 4: Add the extracted details to our main schedule object ---
        // If this is the first time we see this course, initialize it in our object

        if (!scheduleCode[courseCode]) {
          scheduleCode[courseCode] = {
            courseName: courseName,
            courseCode: courseCode,
            timings: [],
          };
        }

        // *** THE CORRECTED LOGIC ***
        // This unconditionally creates and adds a new timing object for every class found.
        // It does not try to merge or group days.
        scheduleCode[courseCode].timings.push({
          doctor: doctor,
          place: place,
          startTime: startTime,
          endTime: endTime,
          days: [dayIndex], // The 'days' array will always contain just the one day for this session.
        });
      }

    }
  }
  const schedule = {};
   // return JSON.stringify(scheduleCode);
  for (const value of Object.values(scheduleCode)){
    const lecture = value; // value is the object scheduleCode[key]
    schedule[lecture.courseName] = lecture;
  }
  // --- Step 5: Return the final, correctly structured object ---
  return JSON.stringify(schedule);
